(() => {
  const app=document.getElementById('app'),modalRoot=document.getElementById('modal-root');let route='home',timer=null,wakeLock=null,scannerControls=null,enemyProcessing=false,activeDraftKey=null,activeDraftCommitted=false;
  const $=(s,p=document)=>p.querySelector(s), $$=(s,p=document)=>[...p.querySelectorAll(s)];
  const state=()=>SFStore.get();
  const allClasses=()=>({...SF_DATA.classes,...Object.fromEntries((state().customContent.classes||[]).filter(x=>x.name).map(x=>[x.name,x]))});
  const allEncounters=()=>[...SF_DATA.encounters,...(state().customContent.monsters||[]).filter(x=>x.name).map((x,i)=>({id:x.id||`custom-${i}-${x.name.toLowerCase().replace(/[^a-z0-9]+/g,'-')}`,name:x.name,cr:x.cr||'Custom',recommended:+x.recommendedLevel||1,art:x.art||'assets/icons/logo.svg',ac:+x.ac||10,hp:+x.hp||10,dex:+x.dex||0,attack:+x.attackBonus||+x.attack||2,damage:x.damage||'1d6',damageType:x.damageType||'bludgeoning',multi:+x.multi||1,soloWard:+x.soloWard||0,reward:x.reward||{gold:0,item:'Private Content Trophy'},custom:true}))];
  const fmtDate=d=>new Date(d).toLocaleDateString([], {month:'short',day:'numeric'});const today=()=>new Date().toISOString().slice(0,10);
  const esc=s=>String(s??'').replace(/[&<>'"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[c]));
  const draftSlug=s=>String(s||'form').toLowerCase().replace(/[^a-z0-9]+/g,'-').replace(/^-|-$/g,'');
  function draftFields(root){return $$('input[id],select[id],textarea[id]',root).filter(el=>el.type!=='file'&&el.type!=='button'&&el.type!=='submit')}
  function fieldValue(el){return el.type==='checkbox'||el.type==='radio'?el.checked:el.value}
  function saveDraft(key,root){if(!key)return;const values={};draftFields(root).forEach(el=>values[el.id]=fieldValue(el));SFStore.update(s=>{s.drafts=s.drafts||{};s.drafts[key]={values,updatedAt:new Date().toISOString()};return s})}
  function clearDraft(key){if(!key)return;SFStore.update(s=>{if(s.drafts)delete s.drafts[key];return s})}
  function restoreDraft(key,root){const draft=state().drafts?.[key]?.values;if(!draft)return false;draftFields(root).forEach(el=>{if(!(el.id in draft))return;if(el.type==='checkbox'||el.type==='radio')el.checked=!!draft[el.id];else if(el.tagName==='SELECT'){if([...el.options].some(o=>o.value===String(draft[el.id])))el.value=String(draft[el.id])}else el.value=draft[el.id]??'';el.dispatchEvent(new Event('change',{bubbles:true}))});return true}
  function bindDraft(root,key,{showNotice=false}={}){const fields=draftFields(root);if(!fields.length)return null;const restored=restoreDraft(key,root);fields.forEach(el=>{el.addEventListener('input',()=>saveDraft(key,root));el.addEventListener('change',()=>saveDraft(key,root))});if(showNotice&&!root.querySelector('.draft-note'))root.insertAdjacentHTML('beforeend',`<div class="draft-note">${restored?'Unsaved draft restored. ':'Draft autosave is on. '}Final submission is still required.</div>`);return key}
  function toast(msg,type='good'){const el=document.createElement('div');el.className=`toast ${type}`;el.textContent=msg;$('#toast-stack').append(el);setTimeout(()=>el.remove(),3000)}
  function icon(name){return ({home:'⌂',workout:'◫',log:'＋',character:'◆',encounters:'⚔',settings:'⚙'})[name]||'•'}
  function xpInfo(){const s=state(),l=s.level,lo=SF_DATA.xpThresholds[l-1],hi=SF_DATA.xpThresholds[l]??lo,pct=hi===lo?100:(s.xp-lo)/(hi-lo)*100;return {lo,hi,pct:Math.max(0,Math.min(100,pct))}}
  function header(){const s=state();return `<header class="topbar"><div class="topbar-row"><div class="brand"><img src="assets/icons/logo.svg"><div><div class="brand-title">StatForge</div><div class="brand-sub">Forge Your Character in Real Life.</div></div></div><div class="level-chip">LV ${s.character?s.level:'—'}</div></div></header>`}
  function nav(){return `<nav class="nav">${['home','workout','log','character','encounters','settings'].map(r=>`<button data-route="${r}" class="${route===r?'active':''}"><span class="ico">${icon(r)}</span><span>${r[0].toUpperCase()+r.slice(1)}</span></button>`).join('')}</nav>`}
  function shell(content){app.innerHTML=header()+`<main class="main">${content}</main>`+nav();document.documentElement.style.setProperty('--accent',state().settings.accent);bindGlobal()}
  function bindGlobal(){$$('[data-route]').forEach(b=>b.onclick=()=>{route=b.dataset.route;render();scrollTo(0,0)});}
  function xpBar(){const s=state(),x=xpInfo();return `<div class="progress"><span style="width:${x.pct}%"></span></div><div class="xp-row"><span>${s.xp.toLocaleString()} XP</span><span>${s.character?`${(x.hi-s.xp).toLocaleString()} to level ${Math.min(20,s.level+1)}`:'Complete the baseline to forge a character'}</span></div>`}
  function showModal(title,body,after,draftKey){modalRoot.innerHTML=`<div class="modal-backdrop"><div class="modal"><div class="modal-head"><div class="modal-title">${title}</div><button class="modal-close">✕</button></div>${body}</div></div>`;document.body.classList.add('no-scroll');activeDraftKey=null;activeDraftCommitted=false;const modal=$('.modal');$('.modal-close').onclick=closeModal;$('.modal-backdrop').onclick=e=>{if(e.target===e.currentTarget)closeModal()};after?.(modal);const key=draftKey===false?null:`modal:${draftSlug(draftKey||title)}`;if(key)activeDraftKey=bindDraft(modal,key,{showNotice:true});modal.addEventListener('click',e=>{const id=e.target.closest('button')?.id||'';if(/^(save-|ready-go|forge-|confirm-|complete-)/.test(id))activeDraftCommitted=true},true);}
  function closeModal(){if(scannerControls?.stop)scannerControls.stop();scannerControls=null;if(activeDraftCommitted&&activeDraftKey)clearDraft(activeDraftKey);activeDraftKey=null;activeDraftCommitted=false;modalRoot.innerHTML='';document.body.classList.remove('no-scroll')}
  function dataURL(file){return new Promise((res,rej)=>{const r=new FileReader();r.onload=()=>res(r.result);r.onerror=rej;r.readAsDataURL(file)})}
  function dateDiff(a,b){return Math.floor((new Date(b)-new Date(a))/86400000)}
  function weightedAverage(arr,key){if(!arr.length)return null;return arr.reduce((n,x)=>n+(+x[key]||0),0)/arr.length}
  function render(){switch(route){case'workout':return renderWorkout();case'log':return renderLog();case'character':return renderCharacter();case'encounters':return renderEncounters();case'settings':return renderSettings();default:return renderHome();}}
  function dueGoals(){const s=state(),d=today(),goals=[],due=id=>!(s.reminders.snoozed[id]>Date.now());if(due('weight')&&!s.logs.weights.some(x=>x.date===d))goals.push({id:'weight',title:'Morning weigh-in',meta:'No XP · trend data'});const lastWaist=s.logs.waists.at(-1);if(due('waist')&&(!lastWaist||dateDiff(lastWaist.date,d)>=14))goals.push({id:'waist',title:'Biweekly waist measurement',meta:'No XP · consistent conditions'});if(due('cpap')&&!s.logs.cpap.some(x=>x.date===d))goals.push({id:'cpap',title:'Log CPAP use',meta:'Recovery · Constitution'});if(due('meal')&&!s.logs.nutrition.some(x=>x.date===d))goals.push({id:'meal',title:'Log your first meal',meta:'Nutrition baseline'});const day=new Date().getDay();if(due('workout')&&day>=1&&day<=5&&!s.workout.history.some(x=>x.date===d&&x.completed))goals.push({id:'workout',title:s.profile.baselineComplete?'Complete today’s planned workout':s.profile.baselineMode?'Continue the three-session baseline':'Choose your Home or Gym Prologue',meta:s.profile.baselineComplete?'1 hour · primary quest':s.profile.baselineMode?`${s.profile.baselineMode==='home'?'45':'60'} minutes · Prologue`:'Three-session character-creation baseline'});if(due('rowcal')&&s.profile.baselineComplete&&s.baseline.records.row_calibration_pending)goals.push({id:'rowcal',title:'Optional 2K row calibration',meta:'Gym visit · not required for character creation'});return goals}
  function renderHome(){const s=state(),goals=dueGoals(),workouts=s.workout.history.filter(x=>x.completed).length,weight=s.logs.weights.at(-1)?.value||s.profile.startWeight,waist=s.logs.waists.at(-1)?.value||s.profile.estimatedWaist;
    shell(`<h1 class="page-title">${greeting()}, ${esc(s.profile.name||'Forgekeeper')}</h1><p class="page-sub">Today’s work comes first. The character gets stronger because you did.</p>
    <section class="card hero-card"><div class="section-title" style="margin-top:0">Today’s goals <span class="badge">${goals.length} open</span></div><div class="list">${goals.length?goals.map(g=>`<div class="goal-row"><div class="check">${g.id==='workout'?'⚔':'·'}</div><div class="goal-info"><div class="goal-title">${g.title}</div><div class="goal-meta">${g.meta}</div></div><div style="display:flex;gap:6px"><button class="btn small ghost" data-snooze="${g.id}">Later</button><button class="btn small" data-goal="${g.id}">Open</button></div></div>`).join(''):'<div class="empty"><strong>Daily board clear</strong>You’ve handled every reminder currently due.</div>'}</div></section>
    <div class="section-title">Character progress</div><section class="card"><div style="display:flex;justify-content:space-between;align-items:end;margin-bottom:9px"><div><div class="tiny">${s.character?`${s.character.name} · ${s.character.species} ${s.character.class}`:'Character creation locked'}</div><div style="font-size:24px;font-weight:950">${s.character?`Level ${s.level}`:'Complete the Prologue'}</div></div><span class="badge">${s.xp} XP</span></div>${xpBar()}</section>
    <div class="grid three" style="margin-top:12px"><div class="metric"><div class="metric-value">${workouts}</div><div class="metric-label">Workouts complete</div></div><div class="metric"><div class="metric-value">${weight}</div><div class="metric-label">Latest weight (lb)</div></div><div class="metric"><div class="metric-value">${waist}</div><div class="metric-label">Latest waist (in)</div></div></div>
    <div class="section-title">Active milestones</div><div class="list">${s.milestones.filter(m=>!m.completedAt).slice(0,4).map(m=>milestoneRow(m)).join('')}</div>`);
    $$('[data-goal]').forEach(b=>b.onclick=()=>{const id=b.dataset.goal;if(id==='workout'||id==='rowcal'){route='workout';render()}else{route='log';render();setTimeout(()=>openQuickLog(id),50)}});$$('[data-snooze]').forEach(b=>b.onclick=()=>{SFStore.update(s=>{s.reminders.snoozed[b.dataset.snooze]=Date.now()+2*60*60*1000;return s});toast('Reminder snoozed for two hours.');render()})
  }
  function greeting(){const h=new Date().getHours();return h<12?'Good morning':h<18?'Good afternoon':'Good evening'}
  function milestoneRow(m){const label=m.status==='pendingProof'?'Proof needed':m.proof?'Proof':'Tracked';return `<div class="list-item"><div class="grow"><div class="list-title">${esc(m.title)}</div><div class="list-sub">${m.tier} · up to $${m.cap} · Reward: ${esc(m.reward)}</div></div><span class="badge ${m.status==='pendingProof'?'danger':m.proof?'warn':''}">${label}</span></div>`}
  function baselinePlans(){return state().profile.baselineMode==='home'?SF_DATA.homeBaseline:SF_DATA.baseline}
  function currentBaseline(){const s=state();return baselinePlans().find(x=>!s.baseline.completed.includes(x.id))}
  function renderBaselineChoice(){shell(`<h1 class="page-title">Choose Your Prologue</h1><p class="page-sub">Both routes unlock character creation after three sessions. Choose one route and keep it for the full baseline.</p><div class="grid two baseline-choice"><section class="card hero-card"><span class="badge">START NOW</span><h2>Home Baseline</h2><p class="list-sub">Three 45-minute sessions using floor space, a wall, a sturdy chair, and a timer. It measures push-ups, plank, balance, leg endurance, and simple conditioning.</p><div class="source-note" style="margin:12px 0">This route unlocks your character immediately after Session III. Your first gym row later becomes a separate rowing calibration.</div><button class="btn full" id="choose-home-baseline">Choose Home Prologue</button></section><section class="card"><span class="badge">FULL EQUIPMENT</span><h2>Gym Baseline</h2><p class="list-sub">Three 60-minute sessions using machines and the Concept2 rower for the most complete starting picture.</p><div class="source-note" style="margin:12px 0">Best for exercise-load recommendations and immediate 2K-row calibration.</div><button class="btn secondary full" id="choose-gym-baseline">Choose Gym Prologue</button></section></div><div class="source-note" style="margin-top:14px">Stop and seek medical help for chest discomfort, fainting, severe shortness of breath, or pain that feels unusual rather than ordinary muscle effort.</div>`);$('#choose-home-baseline').onclick=()=>setBaselineMode('home');$('#choose-gym-baseline').onclick=()=>setBaselineMode('gym')}
  function setBaselineMode(mode){SFStore.update(s=>{s.profile.baselineMode=mode;return s});toast(`${mode==='home'?'Home':'Gym'} Prologue selected.`);render()}
  function weekdayKey(){return ['sunday','monday','tuesday','wednesday','thursday','friday','saturday'][new Date().getDay()]}
  function todaysPlan(){const s=state();if(!s.profile.baselineComplete)return currentBaseline();const key=weekdayKey();if(!SF_DATA.templates[key])return {id:'recovery',title:'Recovery Day',subtitle:'No required job workout. Light activity is optional.',minutes:0,items:[]};const plan={id:key,...JSON.parse(JSON.stringify(SF_DATA.templates[key]))};const now=new Date(),prev=new Date(now);do{prev.setDate(prev.getDate()-1)}while([0,6].includes(prev.getDay()));const prevDate=prev.toISOString().slice(0,10),prevKey=['sunday','monday','tuesday','wednesday','thursday','friday','saturday'][prev.getDay()];if(s.profile.programStartDate&&prevDate>=s.profile.programStartDate&&!s.workout.history.some(x=>x.date===prevDate&&x.completed)&&SF_DATA.templates[prevKey]){const carry=SF_DATA.templates[prevKey].items.find(i=>i.exercise&&!plan.items.some(p=>p.exercise===i.exercise));if(carry){const copy={...JSON.parse(JSON.stringify(carry)),sets:Math.min(2,carry.sets||1),carryover:true,protocol:`Carryover from missed ${prevKey}: ${carry.protocol||'complete clean prescribed reps.'}`};const cool=plan.items.findIndex(i=>i.type==='cooldown');plan.items.splice(cool<0?plan.items.length:cool,0,copy);plan.subtitle=(plan.focus||'Planned workout')+' · includes priority carryover';}}const pushBase=s.baseline.records.pushups_2m||30,plankBase=s.baseline.records.plank_max||75;plan.items.forEach(i=>{if(i.reps==='submax')i.reps=Math.max(5,Math.floor(pushBase*.6));if(i.seconds==='adaptive')i.seconds=plan.id==='friday'?Math.max(20,Math.floor(plankBase*.75)):Math.max(20,Math.floor(plankBase*1.5/(i.sets||1)));});return plan}
  function renderWorkout(){const s=state();if(s.workout.active)return renderActiveWorkout();if(!s.profile.baselineComplete&&!s.profile.baselineMode)return renderBaselineChoice();const plan=todaysPlan();
    const readiness=s.logs.readiness.find(x=>x.date===today());
    shell(`<h1 class="page-title">Workout</h1><p class="page-sub">${s.profile.baselineComplete?'Today’s planned session is revealed. Future days remain hidden.':'Complete the three-part Prologue before character creation.'}</p>
    <section class="card hero-card"><div class="workout-banner"><div><span class="badge">${plan.minutes||0} MIN</span>${!s.profile.baselineComplete?`<span class="badge" style="margin-left:6px">${s.profile.baselineMode==='home'?'HOME':'GYM'} PROLOGUE</span>`:''}<h2 style="margin:10px 0 6px">${plan.title}</h2><div class="list-sub">${plan.subtitle||plan.focus||''}</div></div><img class="exercise-image small" src="${plan.items?.find(i=>i.exercise)?.exercise?SF_DATA.exercises[plan.items.find(i=>i.exercise).exercise].image:'assets/icons/logo.svg'}"></div><div class="divider"></div>
      ${plan.items?.length?`<div class="tiny">${plan.items.filter(i=>i.exercise).length} exercises · warm-up and cooldown included</div><div class="button-row" style="margin-top:12px"><button class="btn secondary" id="preview-workout">Preview</button><button class="btn" id="start-workout">${readiness?'Start Workout':'Check In & Start'}</button></div>${!s.profile.baselineComplete&&!s.baseline.completed.length?'<button class="btn ghost full" style="margin-top:8px" id="change-baseline">Change Prologue Route</button>':''}`:'<div class="empty"><strong>No required session today</strong>Take a recovery day or log an optional walk, mobility session, or family activity.</div>'}
    </section>
    ${s.profile.baselineComplete&&s.baseline.records.row_calibration_pending?`<div class="section-title">Optional calibration</div><section class="card"><div class="list-item"><img class="exercise-image small" src="assets/exercises/rower.svg"><div class="grow"><div class="list-title">2K Row Calibration</div><div class="list-sub">Your Home Prologue unlocked character creation. Complete this 30-minute gym session whenever convenient to refine rowing targets.</div></div></div><div class="button-row" style="margin-top:12px"><button class="btn secondary" id="preview-row-cal">Preview</button><button class="btn" id="start-row-cal">Start Calibration</button></div></section>`:''}
    <div class="section-title">Recent training</div><div class="list">${s.workout.history.slice(-5).reverse().map(w=>`<div class="list-item"><div class="grow"><div class="list-title">${esc(w.title)}</div><div class="list-sub">${fmtDate(w.date)} · ${w.setsLogged||0} sets · ${w.xp||0} XP</div></div><span class="badge ${w.completed?'good':'warn'}">${w.completed?'Complete':'Ended'}</span></div>`).join('')||'<div class="empty">No workouts logged yet.</div>'}</div>`);
    $('#preview-workout')?.addEventListener('click',()=>previewWorkout(plan));$('#start-workout')?.addEventListener('click',()=>readiness?startWorkout(plan):readinessModal(plan));$('#change-baseline')?.addEventListener('click',()=>{SFStore.update(st=>{st.profile.baselineMode=null;return st});render()});$('#preview-row-cal')?.addEventListener('click',()=>previewWorkout(SF_DATA.rowCalibration));$('#start-row-cal')?.addEventListener('click',()=>readiness?startWorkout(SF_DATA.rowCalibration):readinessModal(SF_DATA.rowCalibration));
  }
  function readinessModal(plan){showModal('Pre-Workout Check-In',`<div class="form-grid"><div class="field"><label>Unusual or sharp pain?</label><select id="ready-pain"><option value="none">None</option><option value="mild">Mild — avoid affected movement</option><option value="stop">Yes — do not train normally</option></select></div><div class="field"><label>Muscle soreness</label><select id="ready-sore"><option value="none">None</option><option value="upper">Upper body</option><option value="lower">Lower body</option><option value="core">Core / lower back</option><option value="full">Full body</option></select></div><div class="field"><label>Sleep last night</label><select id="ready-sleep"><option value="8">8+ hours</option><option value="7">7–8 hours</option><option value="6">6–7 hours</option><option value="5">Under 6 hours</option></select></div><div class="field"><label>CPAP use</label><select id="ready-cpap"><option value="full">Full night</option><option value="partial">Part of night</option><option value="none">None</option></select></div><button class="btn full" id="ready-go">Continue</button></div>`,m=>{$('#ready-go',m).onclick=()=>{const rec={date:today(),time:new Date().toISOString(),pain:$('#ready-pain').value,soreness:$('#ready-sore').value,sleep:+$('#ready-sleep').value,cpap:$('#ready-cpap').value};SFStore.update(s=>{s.logs.readiness.push(rec);return s});closeModal();if(rec.pain==='stop'){showModal('Training Adjusted',`<p class="page-sub">Because you reported unusual or sharp pain, StatForge will not launch a normal strength session. Use a gentle walk only if it is medically comfortable, and follow your clinician’s advice.</p><button class="btn full" id="pain-close">Understood</button>`,()=>$('#pain-close').onclick=closeModal)}else startWorkout(adaptPlan(plan,rec));}})}
  function adaptPlan(plan,rec){const p=JSON.parse(JSON.stringify(plan));if(rec.soreness!=='none'||rec.sleep<=5){p.items=p.items.map(i=>i.exercise?{...i,sets:Math.max(1,(i.sets||1)-(rec.sleep<=5?1:0)),adapted:true}:i);p.subtitle=(p.subtitle||p.focus||'')+' · volume adjusted from check-in';}return p}
  function previewWorkout(plan){showModal(plan.title,`<div class="list">${plan.items.map((i,idx)=>{if(i.exercise){const e=SF_DATA.exercises[i.exercise];return `<div class="list-item"><img class="exercise-image small" src="${e.image}"><div class="grow"><div class="list-title">${idx+1}. ${e.name}</div><div class="list-sub">${i.sets||1} set${i.sets===1?'':'s'} · ${i.reps||i.seconds||i.minutes||i.meters||i.prescription||''}${i.protocol?`<br>${i.protocol}`:''}</div></div></div>`}return `<div class="list-item"><div class="grow"><div class="list-title">${i.label}</div><div class="list-sub">${i.minutes} minutes · ${(i.steps||[]).join(' · ')}</div></div></div>`}).join('')}</div>`)}
  async function startWorkout(plan){const alreadyRewarded=state().workout.history.some(w=>w.date===today()&&w.planId===plan.id&&w.completed);const active={plan:JSON.parse(JSON.stringify(plan)),date:today(),startedAt:new Date().toISOString(),itemIndex:0,logs:[],completed:false,xpEligible:!alreadyRewarded};SFStore.update(s=>{s.workout.active=active;return s});if(state().settings.keepAwake&&'wakeLock'in navigator)try{wakeLock=await navigator.wakeLock.request('screen')}catch{}render()}
  function renderActiveWorkout(){const s=state(),a=s.workout.active,item=a.plan.items[a.itemIndex];if(!item)return finishWorkout();const isEx=!!item.exercise,e=isEx?SF_DATA.exercises[item.exercise]:null,completed=a.logs.filter(x=>x.itemIndex===a.itemIndex).length,targetSets=item.sets||1;
    shell(`<h1 class="page-title">${a.plan.title}</h1><p class="page-sub">Step ${a.itemIndex+1} of ${a.plan.items.length}</p><section class="card hero-card">${isEx?`<img class="exercise-image" src="${e.image}"><div class="section-title">${e.name}<span class="badge">${completed}/${targetSets} sets</span></div><div class="list-sub">${item.prescription||`${targetSets} × ${item.reps||item.seconds||item.minutes||item.meters||''} ${item.reps?'reps':item.seconds?'sec':item.minutes?'min':item.meters?'m':''}`}</div>${item.protocol?`<div class="source-note" style="margin-top:12px">${item.protocol}</div>`:''}<div id="set-list">${renderSetLogs(a,a.itemIndex)}</div><div class="sticky-actions"><button class="btn full" id="log-set">Log Set ${Math.min(completed+1,targetSets)}</button><button class="btn ghost full" style="margin-top:8px" id="skip-item">Skip / End Exercise</button></div>`:`<div class="section-title">${item.label}<span class="badge">${item.minutes} MIN</span></div><div class="list">${(item.steps||[]).map(x=>`<div class="list-item"><div class="check">•</div><div class="list-title">${x}</div></div>`).join('')}</div><button class="btn full" style="margin-top:14px" id="complete-block">Complete ${item.label}</button>`}</section>`);
    $('#log-set')?.addEventListener('click',()=>logSetModal(a,item,e,completed));$('#skip-item')?.addEventListener('click',()=>nextWorkoutItem());$('#complete-block')?.addEventListener('click',()=>{const finishBlock=()=>{SFStore.update(s=>{s.workout.active.logs.push({itemIndex:a.itemIndex,type:item.type,completedAt:new Date().toISOString()});s.workout.active.itemIndex++;return s});render()};if(item.type==='rest')startRest((item.minutes||1)*60,finishBlock);else finishBlock()})
  }
  function renderSetLogs(a,idx){const logs=a.logs.filter(x=>x.itemIndex===idx);if(!logs.length)return '';return `<table class="set-table"><thead><tr><th>Set</th><th>Result</th><th>XP</th></tr></thead><tbody>${logs.map((x,i)=>`<tr><td><span class="set-pill done">${i+1}</span></td><td>${x.weight?`${x.weight} lb × `:''}${x.reps||x.seconds||x.minutes||x.meters||''}${x.time?` · ${x.time}`:''}</td><td>+${x.xp}</td></tr>`).join('')}</tbody></table>`}
  function suggestedWeight(exerciseId,targetReps){const logs=state().workout.history.flatMap(w=>w.logs||[]).filter(x=>x.exercise===exerciseId&&x.weight>0);if(!logs.length)return '';const last=logs.at(-1),recent=logs.slice(-2),target=typeof targetReps==='number'?targetReps:8;let weight=last.weight;if(recent.length===2&&recent.every(x=>(x.reps||0)>=target)){weight+=exerciseId==='leg_press'?10:5}return weight}
  function logSetModal(a,item,e,completed){const suggestion=suggestedWeight(item.exercise,item.reps);let fields='';if(e.kind.includes('weighted'))fields+=`<div class="field"><label>${e.kind==='weighted_pair'?'Weight per dumbbell':'Weight'} (lb)</label><input id="set-weight" inputmode="decimal" type="number" min="0" value="${suggestion}"></div>`;if(item.reps||e.kind==='reps'||e.kind==='weighted'||e.kind==='weighted_pair')fields+=`<div class="field"><label>Completed reps</label><input id="set-reps" inputmode="numeric" type="number" min="0" value="${typeof item.reps==='number'?item.reps:''}"></div>`;if(item.seconds||e.kind==='timed'||e.kind==='weighted_timed')fields+=`<div class="field"><label>Seconds${item.seconds?` (target ${item.seconds})`:''}</label><input id="set-seconds" inputmode="numeric" type="number" min="0" value="${typeof item.seconds==='number'?item.seconds:''}"></div>`;if(item.minutes)fields+=`<div class="field"><label>Minutes</label><input id="set-minutes" inputmode="decimal" type="number" min="0" value="${item.minutes}"></div>`;if(item.meters||item.exercise==='row_interval')fields+=`<div class="field"><label>Meters</label><input id="set-meters" inputmode="numeric" type="number" min="0" value="${item.meters||''}"></div><div class="field"><label>Split / time (optional)</label><input id="set-time" placeholder="2:14.5"></div>`;if(item.test==='row_2k')fields+=`<div class="field-inline"><div class="field"><label>Final time</label><input id="set-time" placeholder="8:59.0"></div><div class="field"><label>Average split</label><input id="set-split" placeholder="2:14.7"></div></div><div class="field-inline"><div class="field"><label>Damper</label><input id="set-damper" inputmode="decimal" type="number"></div><div class="field"><label>Stroke rate</label><input id="set-rate" inputmode="numeric" type="number"></div></div>`;
    showModal(`Log ${e.name}`,`<div class="form-grid">${fields}${suggestion?`<div class="source-note">Suggested starting weight: ${suggestion} lb, based on the last logged sets. You can change it.</div>`:''}<button class="btn full" id="save-set">Save Set</button></div>`,m=>{$('#save-set',m).onclick=()=>{const log={itemIndex:a.itemIndex,exercise:item.exercise,at:new Date().toISOString(),weight:+($('#set-weight',m)?.value||0),reps:+($('#set-reps',m)?.value||0),seconds:+($('#set-seconds',m)?.value||0),minutes:+($('#set-minutes',m)?.value||0),meters:+($('#set-meters',m)?.value||0),time:$('#set-time',m)?.value||'',split:$('#set-split',m)?.value||'',damper:+($('#set-damper',m)?.value||0),rate:+($('#set-rate',m)?.value||0)};const usedXp=state().workout.active.logs.reduce((n,x)=>n+(x.xp||0),0);log.xp=state().workout.active.xpEligible!==false?Math.max(0,Math.min(calculateSetXp(log,e),40-usedXp)):0;SFStore.update(s=>{s.workout.active.logs.push(log);return s});if(log.xp)SFStore.addXp(log.xp,workoutTrack(e),`${e.name} set`);closeModal();const newCount=state().workout.active.logs.filter(x=>x.itemIndex===a.itemIndex).length;if(newCount>=targetSetsFor(item))nextWorkoutItem(item,e);else startRest(e.rest||60)}})}
  function targetSetsFor(i){return i.sets||1}function workoutTrack(e){return e.muscles.includes('cardio')?'CON':e.muscles.includes('core')?'CON':'STR'}
  function calculateSetXp(l,e){if(l.weight&&l.reps)return Math.min(5,1+Math.floor(l.reps/10)+Math.floor((l.weight*l.reps)/2500));if(l.reps)return Math.min(4,1+Math.floor(l.reps/15));if(l.seconds)return Math.min(4,1+Math.floor(l.seconds/60));if(l.minutes)return Math.min(4,1+Math.floor(l.minutes/10));if(l.meters)return Math.min(4,1+Math.floor(l.meters/500));return 1}
  function nextWorkoutItem(item,e){SFStore.update(s=>{s.workout.active.itemIndex++;return s});render()}
  function startRest(seconds,onDone){if(!seconds){onDone?onDone():render();return}let remaining=seconds;showModal('Rest Timer',`<div class="timer-label">Next set begins in</div><div class="timer" id="rest-time">${formatSeconds(remaining)}</div><div class="button-row"><button class="btn secondary" id="add-rest">+30 sec</button><button class="btn" id="skip-rest">Skip</button></div>`,m=>{timer=setInterval(()=>{remaining--;$('#rest-time',m).textContent=formatSeconds(remaining);if(remaining<=0){clearInterval(timer);timer=null;if(state().settings.vibration&&navigator.vibrate)navigator.vibrate([180,80,180]);closeModal();onDone?onDone():render()}},1000);$('#add-rest',m).onclick=()=>remaining+=30;$('#skip-rest',m).onclick=()=>{clearInterval(timer);timer=null;closeModal();onDone?onDone():render()}})}
  function formatSeconds(s){return `${Math.floor(s/60)}:${String(s%60).padStart(2,'0')}`}
  function finishWorkout(){
    const s=state(),a=s.workout.active;if(!a)return;
    const exerciseLogs=a.logs.filter(x=>x.exercise),completionXp=a.xpEligible!==false?10:0;
    const record={date:a.date,planId:a.plan.id,title:a.plan.title,startedAt:a.startedAt,endedAt:new Date().toISOString(),setsLogged:exerciseLogs.length,logs:a.logs,completed:true,xp:Math.min(50,exerciseLogs.reduce((n,x)=>n+(x.xp||0),0)+completionXp)};
    let unlockedCharacter=false,completedRowCalibration=false;
    SFStore.update(st=>{
      st.workout.history.push(record);st.workout.active=null;
      if((a.plan.baseline||a.plan.id?.startsWith('base'))&&!st.baseline.completed.includes(a.plan.id)){
        if(!st.profile.baselineMode)st.profile.baselineMode=a.plan.mode||'gym';
        st.baseline.completed.push(a.plan.id);extractBaselineRecords(st,a);
        const required=(st.profile.baselineMode==='home'?SF_DATA.homeBaseline:SF_DATA.baseline).map(x=>x.id);
        if(required.every(id=>st.baseline.completed.includes(id))&&!st.profile.baselineComplete){
          st.profile.baselineComplete=true;st.profile.programStartDate=today();unlockedCharacter=true;
          if(st.profile.baselineMode==='home'&&!st.baseline.records.row_2k)st.baseline.records.row_calibration_pending=true;
        }
      }
      if(a.plan.id==='row-calibration'){extractBaselineRecords(st,a);completedRowCalibration=true}
      return st
    });
    if(completionXp)SFStore.addXp(completionXp,'CON','Workout completed');checkMilestones();wakeLock?.release?.();wakeLock=null;
    const note=unlockedCharacter&&state().profile.baselineMode==='home'?' Character creation is now unlocked; an optional gym row calibration remains available.':completedRowCalibration?' Rowing calibration saved and future targets can now use your 2K result.':'';
    showModal('Workout Complete',`<div class="empty"><strong>${completionXp?`+${completionXp} completion XP`:'Replay complete · no additional XP'}</strong>${record.setsLogged} exercise sets logged. Your detailed set XP was awarded as you trained.${note}</div><button class="btn full" id="finish-close">Return to StatForge</button>`,()=>$('#finish-close').onclick=()=>{closeModal();route=state().profile.baselineComplete&&!state().character?'character':'home';render()},false)
  }

  function extractBaselineRecords(s,a){a.logs.forEach(l=>{if(l.exercise==='pushup'&&l.reps)s.baseline.records.pushups_2m=Math.max(s.baseline.records.pushups_2m||0,l.reps);if(l.exercise==='plank'&&l.seconds)s.baseline.records.plank_max=Math.max(s.baseline.records.plank_max||0,l.seconds);if(l.exercise==='row_2k'&&l.time){s.baseline.records.row_2k=l.time;s.baseline.records.row_split=l.split;s.baseline.records.row_damper=l.damper;s.baseline.records.row_calibration_pending=false}if(l.exercise==='chair_stand'&&l.reps)s.baseline.records.chair_stand_30s=Math.max(s.baseline.records.chair_stand_30s||0,l.reps);if(l.exercise==='wall_sit'&&l.seconds)s.baseline.records.wall_sit_max=Math.max(s.baseline.records.wall_sit_max||0,l.seconds);if(l.exercise==='march_2m'&&l.reps)s.baseline.records.march_2m=Math.max(s.baseline.records.march_2m||0,l.reps);if(l.exercise==='single_leg_balance'&&l.seconds)s.baseline.records.balance_max=Math.max(s.baseline.records.balance_max||0,l.seconds);if(l.exercise==='bodyweight_calf_raise'&&l.reps)s.baseline.records.calf_raise_reps=Math.max(s.baseline.records.calf_raise_reps||0,l.reps)})}
  function renderLog(){shell(`<h1 class="page-title">Log</h1><p class="page-sub">Objective inputs earn XP according to significance. Measurements themselves never award XP.</p><div class="grid two"><button class="btn" id="log-meal">Log Meal</button><button class="btn secondary" id="scan-food">Scan Food</button><button class="btn secondary" id="log-activity">Lifestyle Activity</button><button class="btn secondary" id="log-measure">Measurements</button><button class="btn secondary" id="log-recovery">Sleep & CPAP</button><button class="btn secondary" id="log-photo">Local Progress Photo</button></div>${nutritionSummary()}<div class="section-title">Recent entries</div>${recentLogs()}`);$('#log-meal').onclick=mealModal;$('#scan-food').onclick=scanFoodModal;$('#log-activity').onclick=activityModal;$('#log-measure').onclick=measurementModal;$('#log-recovery').onclick=recoveryModal;$('#log-photo').onclick=progressPhotoModal;$('#complete-nutrition-day')?.addEventListener('click',markNutritionDayComplete)}
  function nutritionSummary(){const s=state(),day=s.logs.nutrition.filter(x=>x.date===today()),sum=sumNutrition(day),complete=s.nutrition.completeDays||[],isComplete=complete.includes(today()),count=complete.length,targets=s.nutrition.targets;return `<div class="section-title">Today’s nutrition <span class="badge ${targets?'good':'warn'}">${targets?'Targets active':`${Math.min(count,7)}/7 complete days`}</span></div><section class="card"><div class="grid three"><div class="metric"><div class="metric-value">${Math.round(sum.calories)}</div><div class="metric-label">Calories</div></div><div class="metric"><div class="metric-value">${Math.round(sum.protein)}g</div><div class="metric-label">Protein</div></div><div class="metric"><div class="metric-value">${Math.round(sum.fiber)}g</div><div class="metric-label">Fiber</div></div></div>${targets?nutrientTargetRows(sum,targets):'<div class="source-note" style="margin-top:13px">Targets unlock after seven days you confirm are fully logged. Partial days never become calorie recommendations.</div>'}<button class="btn ${isComplete?'ghost':'secondary'} full" style="margin-top:12px" id="complete-nutrition-day" ${isComplete?'disabled':''}>${isComplete?'Today Marked Complete':'I’m Done Logging Food Today'}</button></section>`}
  function nutrientTargetRows(sum,t){return `<div style="margin-top:13px">${[['Calories','calories','kcal'],['Protein','protein','g'],['Carbs','carbs','g'],['Fat','fat','g'],['Fiber','fiber','g'],['Sodium','sodium','mg']].map(([n,k,u])=>{const p=Math.min(100,(sum[k]||0)/(t[k]||1)*100);return `<div style="margin:9px 0"><div class="hp-label"><span>${n}</span><span>${Math.round(sum[k]||0)} / ${Math.round(t[k])} ${u}</span></div><div class="nutrition-bar"><span style="width:${p}%"></span></div></div>`}).join('')}</div>`}
  function sumNutrition(arr){const keys=['calories','protein','carbs','fat','fiber','sodium','sugar','satFat','cholesterol','potassium'];return arr.reduce((o,x)=>{keys.forEach(k=>o[k]=(o[k]||0)+(+x[k]||0));return o},{})}
  function markNutritionDayComplete(){const s=state();if(!s.logs.nutrition.some(x=>x.date===today()))return toast('Log at least one meal first.','warn');SFStore.update(st=>{st.nutrition.completeDays=st.nutrition.completeDays||[];if(!st.nutrition.completeDays.includes(today()))st.nutrition.completeDays.push(today());return st});maybeUpdateNutritionTargets();toast('Today marked as fully logged.');render()}
  function recentLogs(){const s=state(),all=[...s.logs.nutrition.map(x=>({at:x.at,title:x.name,sub:`${Math.round(x.calories)} kcal · ${Math.round(x.protein)}g protein`,badge:'Meal'})),...s.logs.activities.map(x=>({at:x.at,title:x.name,sub:`${x.amount} ${x.unit} · +${x.xp} XP`,badge:x.track})),...s.logs.weights.map(x=>({at:x.at,title:`Weight: ${x.value} lb`,sub:'Measurement · no XP',badge:'Trend'})),...s.logs.cpap.map(x=>({at:x.at,title:`CPAP: ${x.use}`,sub:`${x.xp} XP`,badge:'CON'}))].sort((a,b)=>new Date(b.at)-new Date(a.at)).slice(0,12);return `<div class="list">${all.map(x=>`<div class="list-item"><div class="grow"><div class="list-title">${esc(x.title)}</div><div class="list-sub">${x.sub}</div></div><span class="badge">${x.badge}</span></div>`).join('')||'<div class="empty">Nothing logged yet.</div>'}</div>`}
  function openQuickLog(id){if(id==='weight'||id==='waist')measurementModal(id);if(id==='cpap')recoveryModal();if(id==='meal')mealModal()}
  function mealModal(prefill={},draftKey='log-meal'){const saved=state().nutrition.savedMeals;showModal('Log Meal',`<div class="form-grid">${saved.length?`<div class="field"><label>Saved meal</label><select id="saved-meal"><option value="">Choose saved meal…</option>${saved.map((m,i)=>`<option value="${i}">${esc(m.name)}</option>`).join('')}</select></div>`:''}<div class="field"><label>Food or meal name</label><input id="food-name" value="${esc(prefill.name||'')}"></div><div class="field-inline"><div class="field"><label>Servings</label><select id="food-servings"><option>.25</option><option>.5</option><option>.75</option><option selected>1</option><option>1.5</option><option>2</option><option value="package">Whole package</option></select></div><div class="field"><label>Servings in package</label><input id="package-servings" type="number" inputmode="decimal" value="${prefill.packageServings||1}"></div></div>${nutritionFields(prefill)}<div class="button-row"><button class="btn secondary" id="save-meal-template">Save as Reusable Meal</button><button class="btn" id="save-food">Log Meal</button></div></div>`,m=>{const savedSel=$('#saved-meal',m);if(savedSel)savedSel.onchange=()=>{const x=saved[+savedSel.value];if(x){Object.entries(x).forEach(([k,v])=>{const el=$(`#food-${k}`,m);if(el)el.value=v});$('#food-name',m).value=x.name}};$('#save-food',m).onclick=()=>saveMealFromModal(m,false);$('#save-meal-template',m).onclick=()=>saveMealFromModal(m,true)},draftKey)}
  function nutritionFields(p={}){return `<div class="grid two">${[['calories','Calories'],['protein','Protein (g)'],['carbs','Carbs (g)'],['fat','Fat (g)'],['fiber','Fiber (g)'],['sodium','Sodium (mg)'],['sugar','Sugar (g)'],['satFat','Saturated fat (g)'],['cholesterol','Cholesterol (mg)'],['potassium','Potassium (mg)']].map(([k,n])=>`<div class="field"><label>${n} per serving</label><input id="food-${k}" type="number" inputmode="decimal" value="${p[k]??''}"></div>`).join('')}</div>`}
  function saveMealFromModal(m,template){const servings=$('#food-servings',m).value==='package'?+($('#package-servings',m).value||1):+$('#food-servings',m).value;const entry={date:today(),at:new Date().toISOString(),name:$('#food-name',m).value||'Meal',servings};['calories','protein','carbs','fat','fiber','sodium','sugar','satFat','cholesterol','potassium'].forEach(k=>entry[k]=+(m.querySelector(`#food-${k}`).value||0)*servings);let earned=0;SFStore.update(s=>{if(template)s.nutrition.savedMeals.push({...entry,at:undefined,date:undefined,servings:1});else{const used=s.logs.nutrition.filter(x=>x.date===today()).reduce((n,x)=>n+(x.xp||0),0);earned=Math.max(0,Math.min(2,6-used));entry.xp=earned;s.logs.nutrition.push(entry);if(!s.nutrition.baselineStarted)s.nutrition.baselineStarted=today();if((s.nutrition.completeDays||[]).includes(today()))s.nutrition.completeDays=s.nutrition.completeDays.filter(d=>d!==today())}return s});if(!template&&earned)SFStore.addXp(earned,'WIS','Meal logged');if(!template)maybeUpdateNutritionTargets();toast(template?'Reusable meal saved.':`Meal logged${earned?` · +${earned} XP`:' · daily meal XP cap reached'}.`);closeModal();render()}
  async function scanFoodModal(){showModal('Scan Packaged Food',`<video id="scan-video" style="width:100%;border-radius:16px;background:#000" playsinline></video><div class="source-note" style="margin:12px 0">Camera scanning works without a third-party app. Nutrition lookup requires an internet connection; manual UPC entry remains available.</div><div class="field"><label>UPC / EAN</label><input id="manual-code" inputmode="numeric"></div><div class="button-row"><button class="btn secondary" id="start-camera">Start Camera</button><button class="btn" id="lookup-code">Look Up</button></div>`,m=>{$('#lookup-code',m).onclick=()=>lookupBarcode($('#manual-code',m).value);$('#start-camera',m).onclick=async()=>{try{const reader=new ZXingBrowser.BrowserMultiFormatReader();scannerControls=await reader.decodeFromVideoDevice(undefined,$('#scan-video',m),(result,error,controls)=>{if(result){controls.stop();scannerControls=null;lookupBarcode(result.getText())}})}catch(e){toast('Camera scanner unavailable. Enter the barcode manually.','warn')}}})}
  async function lookupBarcode(code){if(!code)return toast('Enter a barcode.','warn');toast('Looking up food…');try{const r=await fetch(`https://world.openfoodfacts.org/api/v2/product/${encodeURIComponent(code)}.json`);const j=await r.json();if(j.status!==1)throw new Error('Not found');const p=j.product,n=p.nutriments||{},serving=+String(p.serving_quantity||1).replace(',','.')||1,pref={name:p.product_name||`Barcode ${code}`,calories:n['energy-kcal_serving']??n['energy-kcal_100g']*serving/100,protein:n.proteins_serving??n.proteins_100g*serving/100,carbs:n.carbohydrates_serving??n.carbohydrates_100g*serving/100,fat:n.fat_serving??n.fat_100g*serving/100,fiber:n.fiber_serving??n.fiber_100g*serving/100,sodium:(n.sodium_serving??n.sodium_100g*serving/100)*1000,sugar:n.sugars_serving??n.sugars_100g*serving/100,satFat:n['saturated-fat_serving']??n['saturated-fat_100g']*serving/100,packageServings:1};clearDraft('modal:scan-packaged-food');clearDraft('modal:log-meal-scanned');closeModal();mealModal(pref,'log-meal-scanned')}catch(e){toast('Product not found. Use manual meal entry.','warn')}}
  function activityModal(){const cats=[...new Set(SF_DATA.activityLibrary.map(x=>x.category))];showModal('Log Lifestyle Activity',`<div class="form-grid"><div class="field"><label>Category</label><select id="act-cat">${cats.map(x=>`<option>${x}</option>`).join('')}</select></div><div class="field"><label>Activity</label><select id="act-id"></select></div><div class="field"><label id="act-amount-label">Amount</label><input id="act-amount" type="number" inputmode="decimal" value="1" min="0"></div><div class="source-note" id="act-preview"></div><button class="btn full" id="save-act">Log Activity</button></div>`,m=>{const cat=$('#act-cat',m),sel=$('#act-id',m),amt=$('#act-amount',m);function calc(a,v){const prior=state().logs.activities.filter(x=>x.date===today()&&x.id===a.id),priorXp=prior.reduce((n,x)=>n+(x.xp||0),0),globalUsed=state().logs.activities.filter(x=>x.date===today()).reduce((n,x)=>n+(x.xp||0),0),globalLeft=Math.max(0,30-globalUsed);let inc=0;if(a.formula){const priorAmount=prior.reduce((n,x)=>n+(+x.amount||0),0),totalReward=Math.min(a.maxXp,Math.floor((priorAmount+v)/a.xpPer));inc=Math.max(0,totalReward-priorXp)}else{const cap=a.dailyCap||1,usedCount=prior.length,units=Math.max(0,Math.min(Math.floor(v||1),cap-usedCount));inc=units*(a.xp||0)}return Math.min(inc,globalLeft)}function fill(){sel.innerHTML=SF_DATA.activityLibrary.filter(x=>x.category===cat.value).map(x=>`<option value="${x.id}">${x.name}</option>`).join('');preview()}function preview(){const a=SF_DATA.activityLibrary.find(x=>x.id===sel.value),v=+amt.value||0,xp=calc(a,v);$('#act-amount-label',m).textContent=`Amount (${a.unit})`;$('#act-preview',m).textContent=xp?`This entry earns ${xp} XP toward ${a.track}. Daily lifestyle XP is capped at 30.`:'This still logs, but its activity or daily XP cap is already reached.'}cat.onchange=fill;sel.onchange=preview;amt.oninput=preview;fill();$('#save-act',m).onclick=()=>{const a=SF_DATA.activityLibrary.find(x=>x.id===sel.value),amount=+amt.value||0,xp=calc(a,amount),entry={date:today(),at:new Date().toISOString(),id:a.id,name:a.name,amount,unit:a.unit,xp,track:a.track};SFStore.update(s=>{s.logs.activities.push(entry);return s});if(xp)SFStore.addXp(xp,a.track,a.name);toast(`${a.name} logged${xp?` · +${xp} XP`:' · XP cap reached'}.`);closeModal();render()}})}
  function measurementModal(focus){const lastW=state().logs.weights.at(-1)?.value||'',lastWa=state().logs.waists.at(-1)?.value||'';showModal('Measurements',`<div class="form-grid"><div class="field"><label>Morning weight (lb)</label><input id="measure-weight" type="number" step=".1" inputmode="decimal" value="${lastW}"></div><div class="field"><label>Waist at belly-button level (in)</label><input id="measure-waist" type="number" step=".1" inputmode="decimal" value="${lastWa}"></div><div class="source-note">Weight is evaluated through a 7-day average. Waist is intended for consistent biweekly measurement. Neither earns XP.</div><button class="btn full" id="save-measure">Save Measurements</button></div>`,m=>{$('#save-measure',m).onclick=()=>{const w=+$('#measure-weight',m).value,wa=+$('#measure-waist',m).value;SFStore.update(s=>{if(w){s.logs.weights=s.logs.weights.filter(x=>x.date!==today());s.logs.weights.push({date:today(),at:new Date().toISOString(),value:w})}if(wa){s.logs.waists=s.logs.waists.filter(x=>x.date!==today());s.logs.waists.push({date:today(),at:new Date().toISOString(),value:wa})}return s});checkMilestones();maybeUpdateNutritionTargets();toast('Measurements saved.');closeModal();render()}})}
  function recoveryModal(){showModal('Sleep & CPAP',`<div class="form-grid"><div class="field"><label>Hours slept</label><select id="sleep-hours"><option>4</option><option>5</option><option selected>6</option><option>7</option><option>8</option><option>9</option></select></div><div class="field"><label>CPAP use</label><select id="cpap-use"><option value="none">None</option><option value="partial">Partial night</option><option value="full">Full night</option></select></div><button class="btn full" id="save-recovery">Save</button></div>`,m=>{$('#save-recovery',m).onclick=()=>{const use=$('#cpap-use',m).value,hours=+$('#sleep-hours',m).value,score=use==='full'?10:use==='partial'?4:0,prior=state().logs.cpap.find(x=>x.date===today()),earned=Math.max(0,score-(prior?.awardedXp||prior?.xp||0));SFStore.update(s=>{s.logs.sleep=s.logs.sleep.filter(x=>x.date!==today());s.logs.cpap=s.logs.cpap.filter(x=>x.date!==today());s.logs.sleep.push({date:today(),at:new Date().toISOString(),hours});s.logs.cpap.push({date:today(),at:new Date().toISOString(),use,xp:score,awardedXp:Math.max(score,prior?.awardedXp||prior?.xp||0)});return s});if(earned)SFStore.addXp(earned,'CON','CPAP use');toast(`Recovery saved${earned?` · +${earned} XP`:' · no duplicate XP'}.`);closeModal();render()}})}
  function progressPhotoModal(){showModal('Local Progress Photo',`<div class="source-note">This image stays in IndexedDB on this device. It is not included in JSON exports.</div><div class="field" style="margin-top:12px"><label>Choose photo</label><input id="progress-file" type="file" accept="image/*" capture="user"></div><button class="btn full" id="save-photo">Save on Device</button>`,m=>{$('#save-photo',m).onclick=async()=>{const f=$('#progress-file',m).files[0];if(!f)return toast('Choose a photo.','warn');await SFStore.putImage(`progress-${Date.now()}`,f);toast('Progress photo saved on this device.');closeModal()}})}
  function maybeUpdateNutritionTargets(){const s=state(),complete=[...(s.nutrition.completeDays||[])].sort();if(complete.length<7)return;const last7=complete.slice(-7),entries=s.logs.nutrition.filter(x=>last7.includes(x.date));if(!entries.length)return;const totals={};last7.forEach(d=>totals[d]=sumNutrition(entries.filter(x=>x.date===d)));const avg=Object.values(totals).reduce((o,x)=>{Object.keys(x).forEach(k=>o[k]=(o[k]||0)+x[k]/7);return o},{});const prior=s.nutrition.targets,lastReview=s.nutrition.lastTargetReview;const due=!prior||!lastReview||dateDiff(lastReview,today())>=14;if(!due)return;let calories=prior?.calories||Math.max(2000,Math.round((avg.calories-200)/50)*50);let trend='Initial target uses seven user-confirmed complete intake days.';const byDate=new Map();s.logs.weights.forEach(x=>byDate.set(x.date,x));const weights=[...byDate.values()].sort((a,b)=>a.date.localeCompare(b.date)).slice(-14);if(prior&&weights.length===14){const first=weights.slice(0,7).reduce((n,x)=>n+x.value,0)/7,last=weights.slice(7).reduce((n,x)=>n+x.value,0)/7,change=last-first;if(change>-0.5){calories-=100;trend=`14-day weight trend was ${change.toFixed(1)} lb; target reduced by 100 kcal.`}else if(change<-2){calories+=100;trend=`14-day weight trend was ${change.toFixed(1)} lb; target increased by 100 kcal.`}else trend=`14-day weight trend was ${change.toFixed(1)} lb; calorie target held steady.`}calories=Math.max(1800,Math.min(3500,Math.round(calories/50)*50));const referenceWeight=Math.max(180,Math.min(s.profile.startWeight,s.logs.weights.at(-1)?.value||s.profile.startWeight)-25),protein=Math.min(200,Math.round(referenceWeight*.7/5)*5),fat=Math.round((calories*.28/9)/5)*5,carbs=Math.max(100,Math.round((calories-protein*4-fat*9)/4/5)*5);SFStore.update(st=>{st.nutrition.targets={calories,protein,carbs,fat,fiber:30,sodium:2300,sugar:Math.round(calories*.1/4),satFat:Math.round(calories*.1/9),updatedAt:new Date().toISOString(),reason:`${trend} Changes use complete-day intake and rolling weight averages; partial logs are excluded.`};st.nutrition.lastTargetReview=today();return st})}
  function renderCharacter(){const s=state();if(!s.profile.baselineComplete)return shell(`<h1 class="page-title">Character</h1><section class="card"><div class="empty"><strong>Character Creation Locked</strong>Complete all three baseline sessions. Your results will shape recommendations but never restrict legal choices.</div><button class="btn full" data-route="workout">Continue Prologue</button></section>`);if(!s.character)return renderCharacterCreator();const c=s.character,stats=SFCombat.characterStats(c,s.level,s.encounters.equipment,s.customContent.classes||[]),x=xpInfo();shell(`<h1 class="page-title">Character</h1><section class="card character-hero"><div id="portrait-slot">${portraitHtml()}</div><div><div class="tiny">${c.species} · ${c.background}</div><h2 style="margin:3px 0">${esc(c.name)}</h2><div class="list-sub">Level ${s.level} ${c.class}</div><div style="margin-top:10px">${xpBar()}</div></div></section><div class="grid three" style="margin-top:12px"><div class="metric"><div class="metric-value">${stats.hp}</div><div class="metric-label">Max HP</div></div><div class="metric"><div class="metric-value">${stats.ac}</div><div class="metric-label">Armor Class</div></div><div class="metric"><div class="metric-value">+${stats.pb}</div><div class="metric-label">Proficiency</div></div></div><div class="section-title">Ability Scores</div><div class="ability-grid">${Object.entries(c.abilities).map(([k,v])=>`<div class="ability"><div class="name">${k}</div><div class="score">${v}</div><div class="mod">${SFCombat.mod(v)>=0?'+':''}${SFCombat.mod(v)}</div></div>`).join('')}</div><div class="section-title">Real-Life Affinities</div><section class="card">${Object.entries(s.tracks).map(([k,v])=>`<div style="margin:8px 0"><div class="hp-label"><span>${k}</span><span>${v} affinity XP</span></div><div class="progress"><span style="width:${Math.min(100,v/5)}%"></span></div></div>`).join('')}<div class="source-note" style="margin-top:12px">Affinities guide recommendations. They do not directly alter your D&D ability scores.</div></section><div class="section-title">Features & Legacy Boons</div><div class="list"><div class="list-item"><div class="grow"><div class="list-title">${esc(c.originFeat||'Origin Feat')}</div><div class="list-sub">From ${esc(c.background)}</div></div><span class="badge">Origin</span></div>${s.legacyBoons.map(b=>`<div class="list-item"><div class="grow"><div class="list-title">${esc(b.title)}</div><div class="list-sub">${esc(b.boon)}</div></div><span class="badge good">Legacy</span></div>`).join('')}</div><div class="section-title">Equipment & Rewards</div><div class="list">${[...s.encounters.equipment,...Object.entries(s.encounters.inventory).filter(([,v])=>v>0).map(([k,v])=>`${k} ×${v}`)].map(x=>`<div class="list-item"><div class="list-title">${esc(x)}</div></div>`).join('')||'<div class="empty">No special gear yet.</div>'}</div>`);loadPortrait()}
  function portraitHtml(){return `<label class="portrait" style="display:grid;place-items:center;text-align:center;padding:8px;cursor:pointer"><span class="tiny">Upload generated portrait</span><input id="portrait-input" type="file" accept="image/*" hidden></label>`}
  async function loadPortrait(){const slot=$('#portrait-slot');if(!slot)return;const blob=await SFStore.getImage('character-portrait');if(blob){const url=URL.createObjectURL(blob);slot.innerHTML=`<label><img class="portrait" src="${url}"><input id="portrait-input" type="file" accept="image/*" hidden></label>`}$('#portrait-input')?.addEventListener('change',async e=>{const f=e.target.files[0];if(f){await SFStore.putImage('character-portrait',f);renderCharacter()}})}
  function recommendBuild(){const s=state(),r=s.baseline.records,t=s.tracks;let cls='Fighter';if((r.row_2k&&timeToSeconds(r.row_2k)<540)||t.CON>t.STR)cls='Ranger';if(t.INT>Math.max(t.STR,t.CON))cls='Wizard';if(t.CHA>Math.max(t.STR,t.CON,t.INT))cls='Bard';if((r.pushups_2m||0)>=35&&t.STR>=t.CON)cls='Paladin';return {class:cls,species:'Human',background:cls==='Fighter'||cls==='Paladin'?'Soldier':cls==='Wizard'?'Sage':'Criminal'}}
  function renderCharacterCreator(){const rec=recommendBuild(),arr=[15,14,13,12,10,8],homeNote=state().baseline.records.row_calibration_pending?'<div class="source-note" style="margin-top:10px">Home Prologue complete. Rowing recommendations will sharpen after your first logged 2K row, but character creation is fully unlocked now.</div>':'';shell(`<h1 class="page-title">Forge a Character</h1><p class="page-sub">Your baseline recommends a build, but every free 5.5e option remains available.</p><section class="card" id="character-form"><div class="source-note">Recommended: <strong>${rec.species} ${rec.class}</strong> with the ${rec.background} background.</div>${homeNote}<div class="form-grid" style="margin-top:13px"><div class="field"><label>Character name</label><input id="char-name" placeholder="Name your hero"></div><div class="field-inline"><div class="field"><label>Species</label><select id="char-species">${SF_DATA.species.map(x=>`<option ${x===rec.species?'selected':''}>${x}</option>`).join('')}</select></div><div class="field"><label>Class</label><select id="char-class">${Object.keys(allClasses()).map(x=>`<option ${x===rec.class?'selected':''}>${x}</option>`).join('')}</select></div></div><div class="field"><label>Background</label><select id="char-bg">${Object.keys(SF_DATA.backgrounds).map(x=>`<option ${x===rec.background?'selected':''}>${x}</option>`).join('')}</select></div><div id="background-note" class="source-note"></div><div class="field-inline"><div class="field"><label>Background +2</label><select id="boost-two"></select></div><div class="field"><label>Background +1</label><select id="boost-one"></select></div></div><div class="section-title">Standard Array</div><div class="grid three">${['STR','DEX','CON','INT','WIS','CHA'].map((k,i)=>`<div class="field"><label>${k}</label><select id="score-${k}">${arr.map((v,j)=>`<option ${i===j?'selected':''}>${v}</option>`).join('')}</select></div>`).join('')}</div><button class="btn full" id="forge-character">Forge Level 1 Character</button></div></section>`);
    const bg=$('#char-bg'),b2=$('#boost-two'),b1=$('#boost-one');
    function fillBoosts(){const info=SF_DATA.backgrounds[bg.value],opts=info.abilities.map(x=>`<option>${x}</option>`).join('');b2.innerHTML=opts;b1.innerHTML=opts;b2.value=info.abilities[0];b1.value=info.abilities[1]||info.abilities[0];$('#background-note').textContent=`Origin feat: ${info.feat}. Ability increases must use ${info.abilities.join(', ')}.`}
    bg.onchange=fillBoosts;fillBoosts();bindDraft($('#character-form'),'page:character-creation',{showNotice:true});
    $('#forge-character').onclick=()=>{const abilities={},vals=[];['STR','DEX','CON','INT','WIS','CHA'].forEach(k=>{abilities[k]=+$(`#score-${k}`).value;vals.push(abilities[k])});if(new Set(vals).size<6)return toast('Use each standard-array value exactly once.','warn');if(b2.value===b1.value)return toast('Choose different abilities for the +2 and +1 increases.','warn');abilities[b2.value]+=2;abilities[b1.value]+=1;const name=$('#char-name').value.trim();if(!name)return toast('Give the character a name.','warn');SFStore.update(s=>{s.character={name,species:$('#char-species').value,class:$('#char-class').value,background:bg.value,originFeat:SF_DATA.backgrounds[bg.value].feat,abilities,bonusHp:0,tough:false,epicBoon:false,createdAt:new Date().toISOString()};return s});clearDraft('page:character-creation');toast('Character forged.');render()}}
  function timeToSeconds(t){const p=String(t).split(':');return p.length===2?(+p[0]*60+parseFloat(p[1])):parseFloat(t)||9999}
  function renderEncounters(){const s=state();if(!s.character)return shell(`<h1 class="page-title">Encounters</h1><section class="card"><div class="empty"><strong>No character yet</strong>Complete the baseline and forge a level 1 character first.</div></section>`);if(s.encounters.current)return renderCombat();shell(`<h1 class="page-title">Encounter Ladder</h1><p class="page-sub">Every fight is visible. Nothing is hard-locked; the danger itself is the gate. First-clear rewards are granted once.</p><div class="encounter-grid">${allEncounters().map(e=>`<div class="encounter-tile" data-enc="${e.id}" style="position:relative"><img src="${e.art}">${s.encounters.cleared.includes(e.id)?'<span class="cleared-mark">CLEARED</span>':''}<div class="encounter-info"><div class="encounter-name">${e.name}</div><div class="encounter-meta">CR ${e.cr} · Recommended level ${e.recommended}</div><span class="badge ${s.level<e.recommended?'danger':'good'}" style="margin-top:8px">${s.level<e.recommended?'Deadly':'Attempt'}</span></div></div>`).join('')}</div>`);$$('[data-enc]').forEach(x=>x.onclick=()=>encounterDetail(allEncounters().find(e=>e.id===x.dataset.enc)))}
  function encounterDetail(e){const s=state(),cleared=s.encounters.cleared.includes(e.id);showModal(e.name,`<img class="exercise-image" src="${e.art}"><div class="grid three" style="margin-top:12px"><div class="metric"><div class="metric-value">${e.ac}</div><div class="metric-label">AC</div></div><div class="metric"><div class="metric-value">${e.hp}</div><div class="metric-label">HP</div></div><div class="metric"><div class="metric-value">CR ${e.cr}</div><div class="metric-label">Threat</div></div></div><div class="source-note" style="margin:12px 0">Recommended solo level ${e.recommended}. ${e.soloWard?`A ${e.soloWard} HP Solo Trial Ward is applied in combat; the displayed monster AC and HP remain its SRD values. `:''}${state().level<e.recommended?'You can enter, but StatForge expects this to be extremely dangerous.':'Your level is within the intended range.'}</div><div class="list-item"><div class="grow"><div class="list-title">First-clear reward</div><div class="list-sub">${e.reward.gold} gp · ${e.reward.item}${e.reward.quantity?` ×${e.reward.quantity}`:''}</div></div><span class="badge ${cleared?'good':''}">${cleared?'Claimed':'Available'}</span></div><button class="btn full" style="margin-top:12px" id="begin-enc">Enter Encounter</button>`,m=>{$('#begin-enc',m).onclick=()=>{SFStore.update(s=>{s.encounters.current=SFCombat.createEncounter(s,e);return s});closeModal();render()}})}
  function renderCombat(){const s=state(),c=s.encounters.current,e=c.enemy,acts=SFCombat.playerActions(c,s);shell(`<h1 class="page-title">${e.name}</h1><p class="page-sub">Round ${c.round+1} · ${c.turn==='player'?'Your turn':'Enemy turn'}</p><section class="card enemy-card"><img class="enemy-art" src="${e.art}"><div><div class="list-title">${e.name}</div><div class="hp-label"><span>Enemy HP</span><span>${c.enemyHp}/${c.enemyMax}</span></div><div class="progress danger"><span style="width:${c.enemyHp/c.enemyMax*100}%"></span></div><div class="hp-label" style="margin-top:14px"><span>${state().character.name}</span><span>${c.playerHp}/${c.playerMax} HP · AC ${c.stats.ac}</span></div><div class="progress"><span style="width:${c.playerHp/c.playerMax*100}%"></span></div></div></section><div class="section-title">Combat log</div><div class="combat-log" id="combat-log">${c.log.map(logLine).join('')||'<div class="log-system">Initiative rolled. Choose an action when your turn begins.</div>'}</div>${c.finished?combatResult(c,e):`<div class="combat-actions">${acts.map(a=>`<button class="btn ${a.id==='dodge'?'secondary':''}" data-action="${a.id}">${a.label}<small>${a.sub}</small></button>`).join('')}</div>`}`);setTimeout(()=>{const log=$('#combat-log');if(log)log.scrollTop=log.scrollHeight},0);$$('[data-action]').forEach(b=>b.onclick=()=>combatAction(b.dataset.action));$('#combat-exit')?.addEventListener('click',()=>{SFStore.update(s=>{s.encounters.current=null;return s});render()});$('#combat-retry')?.addEventListener('click',()=>{SFStore.update(s=>{s.encounters.current=SFCombat.createEncounter(s,e);return s});render()});if(c.turn==='enemy'&&!c.finished&&!enemyProcessing){enemyProcessing=true;setTimeout(runEnemyOnly,500)}}
  function logLine(x){const cls=x.kind==='damage'?'log-damage':x.kind==='heal'?'log-heal':x.kind==='system'?'log-system':'log-hit';if(x.kind==='roll')return `<div class="${cls}">🎲 ${x.label}: ${x.roll.die}${x.roll.extra!==null?` / ${x.roll.extra}`:''} + modifier = <strong>${x.roll.total}</strong></div>`;return `<div class="${cls}">${esc(x.text)}</div>`}
  function combatResult(c,e){return `<section class="card" style="margin-top:12px"><div class="empty"><strong>${c.result==='victory'?'Victory':'Defeat'}</strong>${c.result==='victory'?'First-clear rewards are permanent. Replays remain available but grant nothing additional.':'No XP, gear, or real-life progress was lost.'}</div><div class="button-row">${c.result==='defeat'?'<button class="btn secondary" id="combat-retry">Retry</button>':''}<button class="btn" id="combat-exit">Return to Ladder</button></div></section>`}
  function runEnemyOnly(){const st=state();if(!st.encounters.current||st.encounters.current.turn!=='enemy'){enemyProcessing=false;return}const enemy=SFCombat.enemyTurn(st.encounters.current,st);SFStore.update(x=>{x.encounters.current=enemy.combat;return x});showDiceEvents(enemy.events,()=>{enemyProcessing=false;if(enemy.combat.finished)finishCombatRewards();render()})}
  function combatAction(action){let s=state(),c=s.encounters.current;const result=SFCombat.playerTurn(c,s,action);SFStore.update(st=>{st.encounters.current=result.combat;return st});showDiceEvents(result.events,()=>{if(result.combat.finished){finishCombatRewards();render()}else setTimeout(()=>{const st=state(),enemy=SFCombat.enemyTurn(st.encounters.current,st);SFStore.update(x=>{x.encounters.current=enemy.combat;return x});showDiceEvents(enemy.events,()=>{if(enemy.combat.finished)finishCombatRewards();render()})},300)})}
  function showDiceEvents(events,done){const rolls=events.filter(x=>x.kind==='roll');if(!rolls.length)return done();const r=rolls[0].roll;showModal(rolls[0].label,`<div class="dice-stage"><div class="die d20">${r.die}</div>${r.extra!==null?`<div class="die d20">${r.extra}</div>`:''}</div><div class="empty"><strong>Total ${r.total}</strong>${events.filter(x=>x.kind!=='roll').map(x=>x.text).join('<br>')}</div>`,()=>setTimeout(()=>{closeModal();done()},750))}
  function finishCombatRewards(){const s=state(),c=s.encounters.current;if(c.result!=='victory')return;const e=c.enemy;if(s.encounters.cleared.includes(e.id))return;SFStore.update(st=>{st.encounters.cleared.push(e.id);st.gold+=e.reward.gold;const item=e.reward.item;if(item.includes('Potion')||item==='Antitoxin'||item==='Alchemist’s Fire'){st.encounters.inventory[item]=(st.encounters.inventory[item]||0)+(e.reward.quantity||1)}else if(item==='Mace'){st.encounters.equipment.push('Mace')}else if(!st.encounters.equipment.includes(item))st.encounters.equipment.push(item);return st});toast(`First clear: ${e.reward.gold} gp and ${e.reward.item}${e.reward.quantity?` ×${e.reward.quantity}`:''}.`)}
  function renderSettings(){const s=state();shell(`<h1 class="page-title">Settings</h1><div class="section-title">Profile & Targets</div><section class="card" id="profile-form"><div class="form-grid"><div class="field"><label>Your name</label><input id="profile-name" value="${esc(s.profile.name)}" placeholder="Optional"></div><div class="field-inline"><div class="field"><label>Assessment date</label><input id="profile-assessment" type="date" value="${s.profile.assessmentDate||''}"></div><div class="field"><label>Target waist (in)</label><input id="profile-waist" type="number" step=".1" value="${s.profile.targetWaist}"></div></div><button class="btn full" id="save-profile">Save Profile</button></div></section><div class="section-title">Appearance</div><section class="card"><div class="list-title">Accent color</div><div class="accent-grid" style="margin-top:13px">${['#25d9c7','#28a8ff','#a775ff','#ff5f82','#6fe06f','#ffc95b'].map(c=>`<button class="accent-dot ${s.settings.accent===c?'active':''}" style="background:${c}" data-accent="${c}" aria-label="Accent color"></button>`).join('')}</div></section><div class="section-title">Workout behavior</div><section class="card"><label class="list-item"><div class="grow"><div class="list-title">Vibration rest alerts</div><div class="list-sub">No audio interruptions</div></div><input id="set-vibrate" type="checkbox" ${s.settings.vibration?'checked':''}></label><label class="list-item"><div class="grow"><div class="list-title">Keep screen awake</div><div class="list-sub">During active workouts when supported</div></div><input id="set-awake" type="checkbox" ${s.settings.keepAwake?'checked':''}></label></section><div class="section-title">Milestone rewards</div><div class="list">${s.milestones.map(m=>`<div class="list-item"><div class="grow"><div class="list-title">${esc(m.title)}</div><div class="list-sub">${m.tier} · $${m.cap} cap<br>${esc(m.reward)}${m.completedAt?`<br>Completed ${fmtDate(m.completedAt)}`:''}</div></div><div style="display:flex;gap:6px;flex-direction:column">${m.status==='pendingProof'?`<button class="btn small warn" data-proof-milestone="${m.id}">Add Proof</button>`:''}<button class="btn small ghost" data-edit-milestone="${m.id}">Edit</button></div></div>`).join('')}</div><div class="section-title">Data</div><section class="card"><div class="button-row"><button class="btn secondary" id="export-save">Export Save</button><label class="btn secondary">Import Save<input id="import-save" type="file" accept="application/json" hidden></label></div><button class="btn ghost full" style="margin-top:10px" id="import-content">Import Private Rules Content</button><button class="btn danger full" style="margin-top:10px" id="reset-app">Reset StatForge</button><div class="source-note" style="margin-top:12px">JSON saves contain logs and game data, but never local photos or portraits.</div></section><div class="section-title">About</div><section class="card"><div class="list-sub">StatForge v1.2 · local-first PWA<br>Free 5.5e mechanics and monster data are used under the SRD 5.2.1 Creative Commons license. See docs/ATTRIBUTION.md.</div></section>`);
    bindDraft($('#profile-form'),'page:profile',{showNotice:true});$('#save-profile').onclick=()=>{SFStore.update(st=>{st.profile.name=$('#profile-name').value.trim();st.profile.assessmentDate=$('#profile-assessment').value;st.profile.targetWaist=+$('#profile-waist').value||st.profile.targetWaist;return st});clearDraft('page:profile');toast('Profile saved.');render()};
    $$('[data-accent]').forEach(b=>b.onclick=()=>{SFStore.update(s=>{s.settings.accent=b.dataset.accent;return s});render()});$('#set-vibrate').onchange=e=>SFStore.update(s=>{s.settings.vibration=e.target.checked;return s});$('#set-awake').onchange=e=>SFStore.update(s=>{s.settings.keepAwake=e.target.checked;return s});$('#export-save').onclick=SFStore.exportSave;$('#import-save').onchange=async e=>{try{await SFStore.importSave(e.target.files[0]);toast('Save imported.');render()}catch(err){toast(err.message,'warn')}};$('#reset-app').onclick=()=>showModal('Reset StatForge?',`<p class="page-sub">This permanently deletes local logs and progress on this device. Local photos must be removed separately by clearing site data.</p><button class="btn danger full" id="confirm-reset">Reset Everything</button>`,()=>$('#confirm-reset').onclick=()=>{SFStore.reset();closeModal();render()});$('#import-content').onclick=contentImportModal;$$('[data-edit-milestone]').forEach(b=>b.onclick=()=>editMilestone(b.dataset.editMilestone));$$('[data-proof-milestone]').forEach(b=>b.onclick=()=>proofMilestoneModal(b.dataset.proofMilestone))}
  function editMilestone(id){const m=state().milestones.find(x=>x.id===id);showModal('Edit Named Reward',`<div class="form-grid"><div class="source-note">The milestone and ${m.tier} spending cap of $${m.cap} stay fixed. The specific reward can change.</div><div class="field"><label>Named reward</label><input id="reward-name" value="${esc(m.reward)}"></div><button class="btn full" id="save-reward">Save Reward</button></div>`,x=>$('#save-reward',x).onclick=()=>{SFStore.update(s=>{s.milestones.find(x=>x.id===id).reward=$('#reward-name',x).value;return s});closeModal();render()})}
  function proofMilestoneModal(id){const m=state().milestones.find(x=>x.id===id);showModal('Verify Major Milestone',`<div class="source-note">Add a clear photo such as the scale, tape measure, assessment record, or rower results screen. It remains only on this device and is excluded from save exports.</div><div class="field" style="margin-top:12px"><label>Proof photo</label><input id="proof-file" type="file" accept="image/*" capture="environment"></div><button class="btn full" id="save-proof">Verify & Complete</button>`,x=>$('#save-proof',x).onclick=async()=>{const f=$('#proof-file',x).files[0];if(!f)return toast('Choose a proof photo.','warn');await SFStore.putImage(`milestone-proof-${id}`,f);completeMilestone(id);closeModal();render()})}
  function completeMilestone(id){SFStore.update(st=>{const m=st.milestones.find(x=>x.id===id);if(!m||m.completedAt)return st;m.completedAt=new Date().toISOString();m.status='complete';if(!st.legacyBoons.some(x=>x.id===id)){let boon='Milestone completed';const c=st.character;if(c){if(id==='workouts10'){c.bonusHp=(c.bonusHp||0)+2;boon='+2 maximum HP';}if(id==='push35'){c.abilities.STR=Math.min(20,c.abilities.STR+1);boon='+1 Strength';}if(id==='plank90'){c.abilities.CON=Math.min(20,c.abilities.CON+1);boon='+1 Constitution';}if(id==='row9'){c.abilities.DEX=Math.min(20,c.abilities.DEX+1);boon='+1 Dexterity';}if(id==='assessment'){c.tough=true;boon='Tough feat';}if(id==='waist41'){c.bonusHp=(c.bonusHp||0)+1;boon='+1 maximum HP';}if(id==='waist40'){c.abilities.WIS=Math.min(20,c.abilities.WIS+1);boon='+1 Wisdom';}if(id==='waist39'){const cls=(allClasses()[c.class]||SF_DATA.classes.Fighter);c.abilities[cls.primary]=Math.min(20,c.abilities[cls.primary]+1);boon=`+1 ${cls.primary}`;}if(id==='waist38'){c.epicBoon=true;boon='Epic Legacy: +1 Armor Class';}}st.legacyBoons.push({id,title:m.title,boon,at:m.completedAt});}return st});toast(`Milestone completed: ${state().milestones.find(x=>x.id===id).title}`)}
  function contentImportModal(){showModal('Private Content Import',`<div class="source-note">Paste structured JSON for material you legally own. Imported content stays in this browser and in your manual save exports.</div><div class="field" style="margin-top:12px"><label>Content JSON</label><textarea id="content-json" rows="12" placeholder='{"type":"monster","name":"Example","ac":15,"hp":30,"attack":5,"damage":"1d8+3"}'></textarea></div><button class="btn full" id="save-content">Validate & Import</button><a class="btn ghost full" style="margin-top:8px;text-decoration:none" href="docs/PRIVATE_CONTENT_SCHEMA.json" download>Download Schema Example</a>`,m=>$('#save-content',m).onclick=()=>{try{const j=JSON.parse($('#content-json',m).value),type=({class:'classes',monster:'monsters',item:'items',rule:'rules'})[j.type];if(!type||!state().customContent[type])throw new Error('Supported type: class, monster, item, rule.');SFStore.update(s=>{s.customContent[type].push(j);return s});toast('Private content imported.');closeModal()}catch(e){toast(e.message,'warn')}})}
  async function checkMilestones(){const s=state();for(const m of s.milestones.filter(x=>!x.completedAt)){let done=false;if(m.type==='completion')done=s.baseline.completed.length>=m.target;if(m.type==='workouts')done=s.workout.history.filter(x=>x.completed).length>=m.target;if(m.type==='pushups')done=(s.baseline.records.pushups_2m||0)>=m.target;if(m.type==='plank')done=(s.baseline.records.plank_max||0)>=m.target;if(m.type==='row')done=s.baseline.records.row_2k&&timeToSeconds(s.baseline.records.row_2k)<m.target;if(m.type==='assessment')done=(s.baseline.records.pushups_2m||0)>=35&&(s.baseline.records.plank_max||0)>=90&&s.baseline.records.row_2k&&timeToSeconds(s.baseline.records.row_2k)<540;if(m.type==='waist')done=(s.logs.waists.at(-1)?.value||999)<=m.target;if(done){if(m.proof){if(m.status!=='pendingProof'){SFStore.update(st=>{st.milestones.find(x=>x.id===m.id).status='pendingProof';return st});toast(`Goal reached — add proof for: ${m.title}`,'warn')}}else completeMilestone(m.id)}}}
  window.addEventListener('sf-xp',e=>{toast(`+${e.detail.amount} XP · ${e.detail.reason}`);if(e.detail.levelUp)showModal('Level Up!',`<div class="empty"><strong>Level ${e.detail.newLevel}</strong>Your real-world progress has strengthened your character.</div><button class="btn full" id="level-close">Continue</button>`,()=>$('#level-close').onclick=closeModal)});
  window.addEventListener('sf-state',()=>{});
  if('serviceWorker'in navigator&&location.protocol!=='file:')navigator.serviceWorker.register('./sw.js').catch(()=>{});
  window.addEventListener('beforeinstallprompt',e=>{e.preventDefault();window.sfInstallPrompt=e});
  render();
})();